import { normalizeHexColor } from '@/utils/helper';
import { Component, createSignal, splitProps } from 'solid-js';
import type { InputColorProps } from '../input.types';
import { InputText } from './input-text';

export const InputColor: Component<InputColorProps> = (props => {
  const [p, otherProps] = splitProps(props, ['value', 'onChange', 'onBlur', 'onInput']);
  const initialValue = normalizeHexColor(p.value);
  const [colorValue, setColorValue] = createSignal(initialValue);

  const colorPickerLabel = (
    <label class="flex cursor-pointer">
      <input
        type="color"
        value={colorValue()}
        class="my-auto size-5 cursor-pointer"
        onChange={e => {
          const newValue = normalizeHexColor(e.currentTarget.value);
          setColorValue(newValue);
          if (p.onChange) {
            p.onChange(newValue, e);
          }
        }}
      />
    </label>
  );

  return (
    <InputText
      {...otherProps}
      type={'text'}
      typeOrigin="color"
      value={colorValue()}
      maskOptions={void 0}
      prefixIcon={colorPickerLabel}
      onInput={(value, e) => {
        setColorValue(value);
        if (p.onInput) {
          p.onInput(value, e);
        }
      }}
      onChange={(value, e) => {
        const normalizedValue = normalizeHexColor(value);
        setColorValue(normalizedValue);
        if (p.onChange) {
          p.onChange(normalizedValue, e);
        }
      }}
      onBlur={(value, e) => {
        const normalizedValue = normalizeHexColor(value);
        setColorValue(normalizedValue);
        if (p.onBlur) {
          p.onBlur(normalizedValue, e);
        }
      }}
    />
  );
}) as Component<InputColorProps>;
